        with pytest.raises(TwoFactorAuthError):
            _schedule(scheduler_2fa_unavailable, EIGHT_DAYS_OUT, otp=valid_otp)

    def test_no_review_scheduled_when_2fa_fails(
        self, auth_service_always_fail, mock_clock, invalid_otp
