            scheduler.schedule(
                manager_id="mgr-1",
                reviewee_id=None,
                scheduled_date=EIGHT_DAYS_OUT,
                otp_token=valid_otp,
            )

    def test_missing_date_raises(self, scheduler, valid_otp):
        with pytest.raises((ValueError, TypeError)):
            scheduler.schedule(
                manager_id="mgr-1",
                reviewee_id="emp-1",
                scheduled_date=None,
                otp_token=valid_otp,
            )

    def test_manager_cannot_review_themselves(self, scheduler, valid_otp):
        with pytest.raises((ValueError, Exception)):
            scheduler.schedule(
                manager_id="mgr-1",
                reviewee_id="mgr-1",
                scheduled_date=EIGHT_DAYS_OUT,
                otp_token=valid_otp,
            )

    def test_string_date_is_rejected_or_coerced(self, scheduler, valid_otp):
        """Raw strings should not be silently accepted as dates."""
        with pytest.raises((TypeError, ValueError, AttributeError)):
            scheduler.schedule(
                manager_id="mgr-1",
                reviewee_id="emp-1",
                scheduled_date="2099-01-01",   # string, not a date object
                otp_token=valid_otp,
            )

    @pytest.mark.parametrize("days_ahead", [7, 8, 14, 30, 90, 180, 365])
    def test_parametrized_valid_dates(self, scheduler, valid_otp, days_ahead):
        future_date = TODAY + timedelta(days=days_ahead)
        event = _schedule(scheduler, future_date, otp=valid_otp)
        assert event.scheduled_date == future_date

    @pytest.mark.parametrize("days_ahead", [0, 1, 2, 3, 4, 5, 6])
